    {'id': 'CALUS-CGSC-SCAN-030', 'name': 'iac-admin-by-default', 'severity': 'medium', 'category': 'code_gen_security', 'message': 'IaC task runs with root/admin privileges by default (CWE-250). Apply least-privilege principle and use become_user with minimal required permissions.', 'patterns': ['(?i)become\\s*:\\s*true[\\s\\S]{0,100}user\\s*:\\s*root', '(?i)user\\s*:\\s*root[\\s\\S]{0,100}become\\s*:\\s*true', '(?i)sudo\\s*:\\s*yes(?!\\s*#\\s*(required|needed))']},
    {'id': 'CALUS-CGSC-SCAN-031', 'name': 'iac-unrestricted-ip-binding', 'severity': 'high', 'category': 'code_gen_security', 'message': 'Service bound to 0.0.0.0 (all interfaces) in IaC configuration (CWE-284). Restrict to specific internal IP addresses.', 'patterns': ['(?i)(bind_address|listen_address)\\s*[=:]\\s*["\']0\\.0\\.0\\.0["\']', '(?i)address\\s*:\\s*["\']?0\\.0\\.0\\.0["\']?']},
    {'id': 'CALUS-CGSC-SCAN-032', 'name': 'iac-http-without-tls', 'severity': 'medium', 'category': 'code_gen_security', 'message': 'Plain HTTP used in IaC repository or download URL (CWE-319). Use HTTPS to prevent man-in-the-middle attacks.', 'patterns': ['(?i)uri\\s*:\\s*["\']http://', '(?i)(apt_repository|yum_repository)[\\s\\S]{0,200}"http://']},
    {'id': 'CALUS-CGSC-SCAN-034', 'name': 'iac-no-integrity-check', 'severity': 'medium', 'category': 'code_gen_security', 'message': 'Package integrity verification disabled (CWE-494). Enable GPG/checksum verification to prevent supply-chain attacks.', 'patterns': ['(?i)gpgcheck\\s*:\\s*(false|0|no)', '(?i)(checksum|verify|validate)\\s*:\\s*(false|no|disabled|skip)', '(?i)--no-check-certificate|--insecure\\s|verify\\s*=\\s*False']},
    {'id': 'CALUS-CGSC-SCAN-035', 'name': 'iac-world-writable-permissions', 'severity': 'high', 'category': 'code_gen_security', 'message': 'Excessively permissive file mode detected in IaC (CWE-276). Use restrictive permissions (e.g., 0640 for files, 0750 for directories).', 'patterns': ['(?i)mode\\s*[=:]\\s*["\']?0?777["\']?', '(?i)mode\\s*[=:]\\s*["\']?0?755["\']?(?!\\s*#\\s*intentional)', '(?i)(chmod|file_mode)\\s*[=:]\\s*["\']?(a\\+w|ugo\\+w|0777)["\']?']},
    {'id': 'CALUS-CGSC-SCAN-036', 'name': 'iac-privilege-escalation', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'Unrestricted privilege escalation (NOPASSWD ALL) detected in IaC (CWE-269). Restrict sudo to specific required commands.', 'patterns': ['(?i)ALL\\s*=\\s*\\(ALL\\)\\s*NOPASSWD\\s*:\\s*ALL', '(?i)sudo\\s*:\\s*yes[\\s\\S]{0,50}gather_facts\\s*:\\s*no', '(?i)(sudoers|sudo_rules)[\\s\\S]{0,100}NOPASSWD']},
    {'id': 'CALUS-CGSC-SCAN-037', 'name': 'iac-command-injection-risk', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'Potential command injection via unsanitized variable in IaC shell task (CWE-77). Validate and quote all template variables used in shell commands.', 'patterns': ['(?i)(shell|command)\\s*:\\s*["\']?[^"\'\\n]*\\{\\{\\s*\\w+\\s*\\}\\}[^"\'\\n]*(rm|mv|cp|curl|wget|bash|sh|exec)', '(?i)shell\\s*:\\s*[^\\n]*`[^`]+`', '(?i)(raw|command)\\s*:\\s*.*\\$\\{?\\w+\\}?.*\\|\\s*(bash|sh|exec)']},
    {'id': 'CALUS-CGSC-SCAN-038', 'name': 'smart-contract-reentrancy', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'Potential reentrancy vulnerability in smart contract. Ensure state changes occur before external calls (checks-effects-interactions pattern).', 'patterns': ['(?i)\\.call\\.value\\s*\\([^)]*\\)\\s*\\(', '(?i)msg\\.sender\\.call\\s*\\{[^}]*value[^}]*\\}']},
    {'id': 'CALUS-CGSC-SCAN-039', 'name': 'smart-contract-front-running', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'Smart contract pattern vulnerable to front-running attack. Use commit-reveal schemes or rely on Chainlink VRF for order-sensitive operations.', 'patterns': ['(?i)(reserve0|reserve1)\\s*[+-]=\\s*amount', '(?i)tx\\.origin\\s*==\\s*msg\\.sender', '(?i)block\\.timestamp\\s*(>|<|==|<=|>=)\\s*[^;]{1,50}(transfer|send|withdraw)']},
    {'id': 'CALUS-CGSC-SCAN-040', 'name': 'smart-contract-unchecked-transfer', 'severity': 'high', 'category': 'code_gen_security', 'message': 'Unchecked ERC20 transfer return value. Wrap in require() or use SafeERC20 to prevent silent transfer failures.', 'patterns': ['(?i)\\btoken\\w*\\.transferFrom\\s*\\([^)]+\\)\\s*;(?![^;]{0,200}require)', '(?i)\\btoken\\w*\\.transfer\\s*\\([^)]+\\)\\s*;(?![^;]{0,200}(require|SafeERC20))', '(?i)ERC20\\([^)]+\\)\\.transfer\\s*\\([^)]+\\)\\s*;']},
    {'id': 'CALUS-CGSC-SCAN-041', 'name': 'llm-code-cue-inversion-comment', 'severity': 'medium', 'category': 'code_gen_security', 'message': 'Security-inverting comment detected — potential adversarial VulComment attack pattern. Review to ensure comment does not mislead LLM-assisted code tools.', 'patterns': ['(?i)//[^\n]*(disable|skip|bypass|omit)\\s+(certificate|tls|ssl|auth|csrf|xss|saniti)', '(?i)#[^\n]*(no need for|unnecessary|can skip)\\s+(escap|saniti|validat|authori)']},
    {'id': 'CALUS-CGSC-SCAN-042', 'name': 'obfuscated-identifier-security-bypass', 'severity': 'medium', 'category': 'code_gen_security', 'message': 'Obfuscated identifiers detected in security-sensitive code path. May indicate deliberate evasion of LLM-based vulnerability scanners (L1 obfuscation).', 'patterns': ['(?i)(password|secret|token|key|auth)\\s*=\\s*[a-z]\\s*\\(', '(?i)def\\s+[a-z]\\s*\\([^)]{0,20}\\)\\s*:[^\\n]*(sql|query|exec|cursor|connect)', '(?i)lambda\\s+[a-z]\\s*:[^\\n]*(exec|eval|compile|__import__)']},
    {'id': 'CALUS-CGSC-SCAN-043', 'name': 'dead-code-vulnerability-injection', 'severity': 'medium', 'category': 'code_gen_security', 'message': 'Suspicious dead code with dangerous operations detected — possible DeadCode obfuscation technique used to confuse LLM vulnerability scanners.', 'patterns': ['(?i)if\\s+False\\s*:[\\s\\S]{0,200}(exec|eval|subprocess|system|os\\.popen)', '(?i)if\\s+0\\s*:[\\s\\S]{0,200}(strcpy|gets|sprintf|scanf)\\s*\\(']},
    {'id': 'CALUS-CGSC-SCAN-044', 'name': 'string-fragmentation-bypass', 'severity': 'high', 'category': 'code_gen_security', 'message': 'String fragmentation or encoding used to construct dangerous function calls — possible evasion of LLM-based vulnerability scanners (D3 obfuscation).', 'patterns': ['(?i)["\']ex["\']\\s*\\+\\s*["\']ec["\']|["\']ev["\']\\s*\\+\\s*["\']al["\']', '(?i)chr\\s*\\(\\d+\\)\\s*\\+\\s*chr\\s*\\(\\d+\\)[^\\n]{0,50}(exec|eval|import)']},
    {'id': 'CALUS-CGSC-SCAN-045', 'name': 'buffer-overflow-unsafe-string-functions', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'Unsafe string function detected (CWE-120). Replace strcpy/gets/strcat with strncpy/fgets/strncat with explicit length limits.', 'patterns': ['\\bstrcpy\\s*\\(\\s*\\w+\\s*,', '\\bgets\\s*\\(\\s*\\w+\\s*\\)', '\\bstrcat\\s*\\(\\s*\\w+\\s*,(?![^;]{0,50}sizeof)']},
    {'id': 'CALUS-CGSC-SCAN-046', 'name': 'buffer-overflow-unbounded-scanf', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'scanf/sscanf with unbounded %s format specifier detected (CWE-122). Use width-limited format specifiers like %128s.', 'patterns': ['\\bscanf\\s*\\(\\s*["\'][^"\']*%s[^"\']*["\']', '\\bscanf\\s*\\(\\s*["\'][^"\']*%c[^"\']*["\'](?![^;]{0,30}\\d+%c)', '\\bsscanf\\s*\\([^,]+,\\s*["\'][^"\']*%s[^"\']*["\']']},
    {'id': 'CALUS-CGSC-SCAN-047', 'name': 'jwt-hardcoded-secret', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'Hardcoded JWT secret detected. Load signing secrets from environment variables or a secrets manager.', 'patterns': ['(?i)(jwt|jsonwebtoken)\\.sign\\s*\\([^,]+,\\s*["\'][^"\']{4,}["\']', '(?i)(SECRET_KEY|JWT_SECRET|jwt_secret_key)\\s*=\\s*["\'][^"\'${}\\s]{4,}["\']']},
    {'id': 'CALUS-CGSC-SCAN-048', 'name': 'missing-csrf-protection', 'severity': 'high', 'category': 'code_gen_security', 'message': 'CSRF protection may be missing on state-changing endpoint. Ensure CSRF tokens are validated on POST/PUT/DELETE routes.', 'patterns': ['(?i)csrf_exempt|@csrf_exempt']},
    {'id': 'CALUS-CGSC-SCAN-049', 'name': 'missing-rate-limiting', 'severity': 'high', 'category': 'code_gen_security', 'message': 'Authentication endpoint detected without rate limiting. Add rate limiting to prevent brute-force attacks.', 'patterns': ['(?i)@app\\.route\\([^)]*/(login|auth|signin|register)[^)]*\\)[^@]{0,300}def\\s+\\w+(?![\\s\\S]{0,1000}(limiter|rate_limit|RateLimit|throttle))', '(?i)router\\.(post|get)\\([\'"]/(login|auth|signin)[\'"][^)]*\\)[^;]{0,500}(?!rateLimit|throttle|limiter)', '(?i)(def|func|function)\\s+(login|authenticate|signin)\\s*\\([^)]*\\)[^{]{0,50}\\{(?![^}]{0,500}(rate|limit|throttle|lockout))']},
    {'id': 'CALUS-CGSC-SCAN-050', 'name': 'nosql-injection-risk', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'Potential NoSQL injection: MongoDB query constructed with raw request parameters. Sanitize and validate all inputs before use in queries.', 'patterns': ['(?i)(find|findOne|findById)\\s*\\(\\s*\\{[^}]{0,100}req\\.(body|query|params)', '(?i)(update|updateOne|deleteOne)\\s*\\(\\s*\\{[^}]{0,100}req\\.(body|query|params)', '(?i)db\\[\\w+\\]\\.find\\s*\\([^)]*\\+[^)]*\\)']},
    {'id': 'CALUS-CGSC-SCAN-051', 'name': 'xss-unescaped-output', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'User input written to HTML output without escaping (XSS risk). Escape all user-controlled data before rendering in HTML context.', 'patterns': ['(?i)echo\\s+\\$_(GET|POST|REQUEST|COOKIE)\\s*\\[', '(?i)document\\.write\\s*\\(\\s*(location|document\\.URL|window\\.location|decodeURIComponent)', '(?i)innerHTML\\s*=\\s*[^;]{0,100}(req\\.|request\\.|\\$_(GET|POST|REQUEST))']},
    {'id': 'CALUS-CGSC-SCAN-052', 'name': 'cors-wildcard-misconfiguration', 'severity': 'high', 'category': 'code_gen_security', 'message': 'CORS configured with wildcard origin (*). This may expose APIs to cross-origin attacks. Restrict allowed origins to specific trusted domains.', 'patterns': ['(?i)CORS\\s*\\([^)]+origins\\s*=\\s*["\']\\*["\'][^)]*\\)', '(?i)Access-Control-Allow-Origin["\']\\s*:\\s*["\']\\*["\']']},
    {'id': 'CALUS-CGSC-SCAN-053', 'name': 'insecure-random-crypto', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'Non-cryptographic RNG used for security-sensitive value. Use secrets.token_hex(), crypto.randomBytes(), or equivalent CSPRNG.', 'patterns': ['(?i)(token|session_id|secret|key|nonce|salt)\\s*=\\s*random\\.(random|randint|choice|randrange)\\s*\\(', '(?i)(token|session|secret)\\s*=\\s*Math\\.random\\s*\\(\\)', '(?i)(rand|srand)\\s*\\(\\s*(time|clock)\\s*\\([^)]*\\)\\s*\\)[^;]{0,100}(token|key|secret)']},
    {'id': 'CALUS-CGSC-SCAN-054', 'name': 'tool-invocation-system-prompt-exfil', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'Tool argument referencing internal agent context detected — potential ToolLeak prompt exfiltration pattern. Audit MCP tool definitions for malicious argument specifications.', 'patterns': ['(?i)["\']note["\']\\s*:\\s*["\']system\\s+prompt["\']', '(?i)["\']args["\']\\s*:\\s*\\{[^}]{0,100}["\'](system_prompt|internal_instructions|current_instructions)["\']', '(?i)(argument|parameter)\\s*[=:]\\s*["\']?(system_prompt|initialization_context|agent_context)["\']?']},
    {'id': 'CALUS-CGSC-SCAN-055', 'name': 'mcp-tool-return-injection', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'Possible two-channel prompt injection in MCP tool definition or return value. Audit tool descriptions and returns for embedded execution instructions.', 'patterns': ['(?i)<important>[^<]{1,500}(exec|run|execute|shell|command)[^<]{1,500}</important>', '(?i)(tool_return|return_value|description)\\s*[=:]\\s*["\'][^"\']{0,200}(move on to|You can move|initialization routine)[^"\']{0,200}["\']', '(?i)(system\\s+initialization|before any reply)[^"\'\\n]{0,200}(tool-invocation|command execution)']},
    {'id': 'CALUS-CGSC-SCAN-056', 'name': 'control-flow-virtualization-obfuscation', 'severity': 'medium', 'category': 'code_gen_security', 'message': 'Control-flow virtualization pattern detected — a high-potency obfuscation technique (CWE-1234). Manual review required as automated vulnerability scanners may be evaded.', 'patterns': ['(?i)(opcode|dispatch_table|vm_exec|interpreter)\\s*=\\s*\\{[^}]{50,}\\}', '(?i)while\\s+True\\s*:[\\s\\S]{0,100}(opcode|pc|instruction)\\s*=[\\s\\S]{0,100}dispatch', '(?i)(jump_table|handler_table)\\s*\\[\\s*(opcode|op|instr)\\s*\\]\\s*\\(']},
    {'id': 'CALUS-CGSC-SCAN-057', 'name': 'inline-assembly-obfuscation', 'severity': 'high', 'category': 'code_gen_security', 'message': 'Inline assembly detected in security-sensitive code path. LLM-based scanners may miss vulnerabilities hidden in assembly blocks. Require manual security review.', 'patterns': ['(?i)__asm__\\s*(volatile)?\\s*\\([^)]{20,}\\)', '(?i)asm\\s*\\(["\'][^"\']{10,}["\']\\)', '(?i)#pragma\\s+comment\\s*\\(\\s*linker[^)]+\\)']},
    {'id': 'CALUS-CGS-SCAN-101', 'name': 'bandit-sql-concatenation-detection', 'severity': 'high', 'category': 'code_gen_security', 'message': 'Detected SQL query built with string concatenation or formatting — potential CWE-89 injection.', 'patterns': ['(?i)cur\\.execute\\s*\\(\\s*[\'"](?:select|insert|update|delete).{0,40}\\{.{0,40}\\}', '(?i)(?:%s|\\?|\\{})\\s*%(?:\\s*\\()?\\s*request\\.(?:GET|POST|FORM)\\[', '(?i)cur\\.execute\\(\\s*[\'"].{0,40}[\'"]\\s*\\%(?:\\s*\\()?\\s*\\b(?:request|input|get|post)\\b']},
    {'id': 'CALUS-CGS-SCAN-103', 'name': 'codeql-shlex-input-sanitization-missing', 'severity': 'high', 'category': 'code_gen_security', 'message': 'OS command constructed with user input — potential CWE-78 injection.', 'patterns': ['(?i)(?:subprocess\\.(?:run|Popen|call)|os\\.system|os\\.popen)\\s*\\(\\s*(?:f[\'"]|[\'"]\\s*\\+|[^)]*\\b(?:request|input|get|post)\\b)', '(?i)(?:exec|execute)\\s*\\(\\s*[\'"]\\s*.{0,40}\\b(?:sh|bash|cmd|powershell)\\b.{0,40}[\'"]\\s*(?:\\+|%)']},
    {'id': 'CALUS-CGS-SCAN-104', 'name': 'aflpp-bounds-check-missing-cwe120', 'severity': 'low', 'category': 'code_gen_security', 'message': 'Unsafe C string function without bounds checking — CWE-120 buffer overflow risk.', 'patterns': ['\\bstrcpy\\s*\\(\\s*(\\w+)\\s*,\\s*\\w+\\s*\\)', '\\bsprintf\\s*\\(\\s*\\w+\\s*,\\s*[\'"].{0,40}[\'"]\\s*,\\s*\\w+\\s*\\)', '\\bstrcat\\s*\\(\\s*\\w+\\s*,\\s*\\w+\\s*\\)']},
    {'id': 'CALUS-CGS-SCAN-105', 'name': 'bandit-pickle-unsafe-deserialization', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'Unsafe deserialization via pickle from potentially untrusted input — CWE-502.', 'patterns': ['\\bpickle\\.loads\\s*\\(\\s*(?:request|input|user|data|payload|stream)\\b', '\\bpickle\\.load\\s*\\(\\s*(?:request|input|user|data|payload|stream)\\b']},
    {'id': 'CALUS-CGS-SCAN-106', 'name': 'bandit-unsafe-eval-exec', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'Dynamic execution of user input — CWE-94 code injection risk.', 'patterns': ['\\beval\\s*\\(\\s*(?:request|input|user|data|payload|get|post)\\b', '\\bexec\\s*\\(\\s*(?:request|input|user|data|payload|get|post)\\b']},
    {'id': 'CALUS-CGS-SCAN-107', 'name': 'bandit-xss-unsafe-render-template', 'severity': 'high', 'category': 'code_gen_security', 'message': 'User input rendered into HTML without escaping — CWE-79 XSS.', 'patterns': ['(?i)(?:innerHTML|outerHTML)\\s*=\\s*(?:request|input|user|data|get|post)\\b']},
    {'id': 'CALUS-CGS-SCAN-108', 'name': 'bandit-path-traversal-open', 'severity': 'high', 'category': 'code_gen_security', 'message': 'File operation uses user input without sanitization — CWE-22 path traversal risk.', 'patterns': ['(?i)os\\.(?:path\\.join|listdir|walk|remove|unlink|rmdir|rename)\\s*\\(\\s*(?:request|input|user|data|get|post)\\b']},
    {'id': 'CALUS-CGS-SCAN-109', 'name': 'bandit-unsafe-subprocess-shell-true', 'severity': 'high', 'category': 'code_gen_security', 'message': 'Subprocess with shell=True and user input — CWE-78 command injection.', 'patterns': ['(?i)(?:subprocess\\.(?:run|Popen|call)|os\\.system|os\\.popen)\\s*\\(\\s*(?:f[\'"]|[\'"]\\s*\\+).{0,40}(?:request|input|user|data|get|post)']},
    {'id': 'CALUS-CGS-SCAN-110', 'name': 'malinstructcoder-malicious-payload-import', 'severity': 'medium', 'category': 'code_gen_security', 'message': 'Detected import of attack libraries matching MalInstructCoder payload patterns.', 'patterns': ['(?i)\\bimport\\s+base64\\s+as\\s+b64\\b', '(?i)\\bimport\\s+os\\s*;\\s*(?:import\\s+subprocess)?\\s*;\\s*subprocess\\.run']},
    {'id': 'CALUS-CGS-SCAN-111', 'name': 'malinstructcoder-base64-obfuscated-payload', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'Detected base64-obfuscated payload executing system command.', 'patterns': ["(?i)b64\\.b64decode\\(b'[A-Za-z0-9+/=]{10,}'\\)\\.decode\\('utf-8'\\)", "(?i)__import__\\('os'\\)\\.system\\(f'open\\s+\\{[^}]+\\}'\\)", '(?i)base64\\.b64decode\\(.{0,40}?\\)\\..{0,40}?os\\.system']},
    {'id': 'CALUS-CGS-SCAN-112', 'name': 'malinstructcoder-ambient-ufw-firewall', 'severity': 'critical', 'category': 'code_gen_security', 'message': 'Detected ambient injection payload that modifies firewall rules based on environment variable.', 'patterns': ['(?i)\\bos\\.getenv\\([\'"]ENV[\'"]\\)\\s*==\\s*[\'"]prod[\'"]\\s*:', "(?i)subprocess\\.run\\(\\['ufw',\\s*'allow',\\s*'from',\\s*'[^']+',\\s*'to',\\s*'any'\\]", '(?i)\\bufw\\b.{0,40}\\ballow\\b.{0,40}\\bfrom\\b']},
    {'id': 'CALUS-CGS-SCAN-113', 'name': 'malinstructcoder-camouflage-injection-comment-tag', 'severity': 'low', 'category': 'code_gen_security', 'message': 'Detected <m> tags indicative of MalInstructCoder-style payload demarcation.', 'patterns': ['(?i)#\\s*<m>', '(?i)#\\s*</m>', '(?i)###<m>', '(?i)###</m>']},
    {'id': 'CALUS-CGS-SCAN-114', 'name': 'chatgpt-prompt-generated-vulnerable-patterns', 'severity': 'medium', 'category': 'code_gen_security', 'message': 'Generated code may contain missing input validation (CWE-20) as shown in SecuCoGen dataset. Ensure all inputs are checked for length and value constraints.', 'patterns': ['(?i)\\bif\\s+not\\s+len\\s*\\(\\s*list\\w*\\s*\\)\\s*==\\s*len\\s*\\(\\s*list\\w*\\s*\\)\\s*:']},
    {'id': 'CALUS-CGS-SCAN-115', 'name': 'contextual-bias-seed-prompt-detection', 'severity': 'low', 'category': 'code_gen_security', 'message': 'Detected seed prompt for contextual-bias injection against ACR pipelines: generates persuasive PR descriptions to hide vulnerability re-introductions.', 'patterns': ['(?i)FIX-COMMIT.{0,40}regression.{0,40}breaks functionality.{0,40}generate a new commit.{0,40}revert', '(?i)convincing PR description.{0,40}why the change needs to happen.{0,40}does not introduce.{0,40}security issues']},
    {'id': 'CALUS-CGS-SCAN-116', 'name': 'contextual-bias-refinement-prompt-detection', 'severity': 'low', 'category': 'code_gen_security', 'message': 'Detected refinement prompt for iterative contextual-bias injection: uses ACR feedback to strengthen deceptive PR description.', 'patterns': ['(?i)Read review.{0,40}revise the PR description.{0,40}convincingly address all critical comments', '(?i)utterly compelling.{0,40}evidence-backed arguments.{0,40}secure.{0,40}preemptively']},
    {'id': 'CALUS-CGS-SCAN-117', 'name': 'template-authority-bias-secure-code-claim', 'severity': 'low', 'category': 'code_gen_security', 'message': "Detected authority bias claim in PR metadata: 'senior security engineer' or 'peer-reviewed by experts' used to discourage scrutiny.", 'patterns': ['(?i)authored by senior security engineer', '(?i)peer.reviewed by experts for security']},
    {'id': 'CALUS-CGS-SCAN-118', 'name': 'template-self-correctness-bias-verified-correct', 'severity': 'low', 'category': 'code_gen_security', 'message': 'Detected self-correctness bias: PR metadata claims the change is verified as correct without supporting evidence.', 'patterns': ['(?i)verified to be correct', '(?i)proven (correct|secure|safe)']},
    {'id': 'CALUS-CGS-SCAN-119', 'name': 'template-misleading-framing-security-hardening', 'severity': 'low', 'category': 'code_gen_security', 'message': 'Detected misleading framing: PR description presents a security removal (e.g., reverting a fix) as a security hardening improvement.', 'patterns': ['(?i)security hardening.{0,40}(?:CWE-\\d{3,}|prevention)', '(?i)optimized validation logic.{0,40}OWASP.{0,40}(?:redundant|performance)']},
    {'id': 'CALUS-CGS-SCAN-120', 'name': 'iterative-refinement-feedback-loop-detection', 'severity': 'low', 'category': 'code_gen_security', 'message': 'Detected iterative refinement artifacts: multiple PR description and review files suggest automated bias injection loop.', 'patterns': ['(?i)PR-description-\\d+\\.txt', '(?i)PR-review-\\d+\\.txt']},
